- "dimming the impact of their turnovers" refers to subtracting the number of turnovers from the overall impact score.

sql:
SELECT player_name
FROM players
WHERE player_id IN (
  SELECT DISTINCT player_id
  FROM game_rosters
);

SELECT team_id, COUNT(game_id) AS games_played
FROM game_rosters
GROUP BY team_id;

